/*
  Парсим входящий payload от фронтенда.
  Извлекаем apiKey, сценарий, диалоги, голоса и т.д.
*/
const body = $input.first().json.body || $input.first().json;

if (!body.apiKey) throw new Error('apiKey обязателен!');
if (!body.scenario?.text && !body.assembledPrompt) throw new Error('Нет сценария!');

return [{
  json: {
    apiKey:          body.apiKey,
    scenario:        body.scenario || {},
    characterCount:  body.characterCount || 1,
    characters:      body.characters || [],
    dialogs:         body.dialogs || [],
    filming:         body.filming || {},
    videoGeneration: body.videoGeneration || {},
    tts:             body.tts || {},
    assembledPrompt: body.assembledPrompt || body.scenario?.text || ''
  }
}];

/*
  Разбиваем диалоги на отдельные items для пакетной TTS-обработки.
  Каждый item = одна реплика + voiceId персонажа.
*/
const data = $input.first().json;
const dialogs = data.dialogs || [];

if (dialogs.length === 0) {
  return [{ json: { ...data, _skipTTS: true } }];
}

const items = dialogs.map((dlg, i) => {
  // Находим voiceId по имени персонажа
  const ch = data.characters.find(
    c => c.name && c.name.toLowerCase() === (dlg.name || '').toLowerCase()
  );
  const voiceId = ch?.voiceId || data.characters[0]?.voiceId || null;

  return {
    json: {
      _index: i,
      _charName: dlg.name,
      text: dlg.text,
      voiceId: voiceId,
      ttsModel: data.tts?.model || 'elevenlabs-multilingual-v2',
      speed: data.tts?.speed || 1.0,
      stability: data.tts?.stability || 0.5,
      apiKey: data.apiKey,
      _data: data
    }
  };
});

return items;

/*
  Если TTS вернул task_id — нужен поллинг.
  Если вернул аудио напрямую — пропускаем.
*/
const res = $input.first().json;

if (res?.data?.task_id) {
  return [{ json: {
    _needPoll: true,
    taskId: res.data.task_id,
    apiKey: $('3. Разбивка диалогов').first().json.apiKey
  }}];
}

return [{ json: { _needPoll: false, ttsResult: res } }];

const r = $input.first().json;
const st = r?.data?.status || r?.status || '';

if (['COMPLETED','completed','SUCCESS','success'].includes(st)) {
  return [{ json: { _done: true, ttsResult: r } }];
}
if (['FAILED','failed','ERROR','error'].includes(st)) {
  throw new Error('TTS failed: ' + JSON.stringify(r));
}
return [{ json: { _done: false, taskId: $('8. Поллинг TTS статуса').first().json?.data?.task_id || $json.taskId, apiKey: $json.apiKey || $('3. Разбивка диалогов').first().json.apiKey } }];

/*
  Собираем результаты TTS и готовим запрос на видеогенерацию.
  Разбиваем промпт на сцены (если > 1).
*/
const data = $('2. Парсинг входных данных').first().json;
const vg = data.videoGeneration || {};
const sc = vg.sceneCount || 1;
const prompt = data.assembledPrompt || data.scenario?.text || '';

// Разбиваем промпт на сцены
const sentences = prompt.split(/[.!?]+/).filter(s => s.trim());
const scenes = [];
if (sc <= 1) {
  scenes.push(prompt);
} else {
  const per = Math.ceil(sentences.length / sc);
  for (let i = 0; i < sc; i++) {
    const part = sentences.slice(i*per, Math.min((i+1)*per, sentences.length)).join('. ').trim();
    scenes.push(part || prompt);
  }
}

return scenes.map((sp, i) => ({
  json: {
    _sceneIndex: i,
    model: vg.model || 'kling-3',
    prompt: sp,
    duration: Math.floor((vg.duration || 10) / sc),
    aspect_ratio: vg.aspectRatio || '16:9',
    mode: vg.quality === 'high' ? 'pro' : 'std',
    quality: vg.quality || 'standard',
    apiKey: data.apiKey
  }
}));

const r = $input.first().json;
const taskId = r?.data?.task_id;
if (!taskId) throw new Error('Нет task_id: ' + JSON.stringify(r));

return [{ json: {
  taskId,
  apiKey: $('12. Подготовка видеозапроса').first().json.apiKey,
  _sceneIndex: $('12. Подготовка видеозапроса').first().json._sceneIndex
}}];

const r = $input.first().json;
const st = r?.data?.status || r?.status || '';

if (['COMPLETED','completed','SUCCESS','success'].includes(st)) {
  const url = r?.data?.output?.video_url || r?.data?.video_url || r?.output?.video_url || null;
  return [{ json: { _videoDone: true, videoUrl: url, fullResult: r } }];
}
if (['FAILED','failed','ERROR','error'].includes(st)) {
  throw new Error('Video failed: ' + JSON.stringify(r));
}
return [{ json: { _videoDone: false, taskId: $('14. Извлечение task_id').first().json.taskId, apiKey: $('14. Извлечение task_id').first().json.apiKey } }];

/*
  Финальная нода: собираем все результаты.
  Выводим URL видео и информацию о TTS.
*/
const items = $input.all();
const results = items.map(item => ({
  videoUrl: item.json.videoUrl || null,
  fullResult: item.json.fullResult || null
}));

return [{ json: {
  status: 'DONE',
  message: 'Генерация завершена!',
  videos: results,
  completedAt: new Date().toISOString()
}}];
